import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Upload Settings","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/index.md","filePath":"ta/upload/index.md","lastUpdated":1781962217000}'),t={name:"ta/upload/index.md"};function o(n,a,d,s,h,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="upload-settings" tabindex="-1">Upload Settings <a class="header-anchor" href="#upload-settings" aria-label="Permalink to &quot;Upload Settings&quot;">​</a></h1><p>இந்த பகுதி System Settings பக்கத்தில் உள்ள channel வரிசையையே பின்பற்றுகிறது. அதனால் நீங்கள் அமைக்க வேண்டிய storage provider பக்கத்துக்கு நேராக செல்லலாம்.</p><h2 id="இந்த-பகுதி-எப்படி-அமைக்கப்பட்டுள்ளது" tabindex="-1">இந்த பகுதி எப்படி அமைக்கப்பட்டுள்ளது <a class="header-anchor" href="#இந்த-பகுதி-எப்படி-அமைக்கப்பட்டுள்ளது" aria-label="Permalink to &quot;இந்த பகுதி எப்படி அமைக்கப்பட்டுள்ளது&quot;">​</a></h2><ul><li>ஒவ்வொரு provider-க்கும் தனி பக்கம் உள்ளது. 13 upload channels-ஐ தனியாக வைத்திருப்பதால் setup steps தெளிவாக இருக்கும்.</li><li>Screenshots <code>../../image/upload/provider-name/</code> கீழ் உள்ளன; ஒவ்வொரு பக்கமும் அவற்றை local path மூலம் பயன்படுத்துகிறது.</li><li>தமிழ் ஆவணத்தில் UI field names மற்றும் service names தேவையான இடங்களில் English-லேயே வைக்கப்பட்டுள்ளன.</li></ul><h2 id="channel-directory" tabindex="-1">Channel Directory <a class="header-anchor" href="#channel-directory" aria-label="Permalink to &quot;Channel Directory&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="இந்த-அத்தியாயத்தில்-உள்ளவை" tabindex="-1">இந்த அத்தியாயத்தில் உள்ளவை <a class="header-anchor" href="#இந்த-அத்தியாயத்தில்-உள்ளவை" aria-label="Permalink to &quot;இந்த அத்தியாயத்தில் உள்ளவை&quot;">​</a></h2><ul><li>ஒவ்வொரு upload channel-ஐ சேர்ப்பது எப்படி.</li><li>channel சேர்ப்பதற்கு முன் எந்த credentials, keys, அல்லது IDs தேவை.</li><li>channel upload-க்கு தயாரா என்பதை சரிபார்ப்பது எப்படி.</li></ul><p>Troubleshooting, quota strategy, மற்றும் best practices தேவையான பக்கங்களில் தனியாக கொடுக்கப்பட்டுள்ளன.</p>',9)])])}const f=e(t,[["render",o]]);export{u as __pageData,f as default};
